insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(5506, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which structure is primarily responsible for warming, humidifying, and filtering inhaled air?', '["Larynx", "Nasal cavity", "Trachea", "Bronchioles"]'::jsonb, 1, 'The nasal cavity''s turbinates and mucosa warm, humidify, and filter air before it reaches the lower airway.', 'Pre-Council', '🎓', true),
(5507, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The epiglottis functions primarily to:', '["Produce sound", "Prevent food/fluid from entering the trachea during swallowing", "Warm inhaled air", "Filter particulate matter"]'::jsonb, 1, 'The epiglottis folds over the laryngeal inlet during swallowing, directing food and fluid into the oesophagus rather than the airway.', 'Pre-Council', '🎓', true),
(5508, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which cartilage forms the ''Adam''s apple'' and protects the vocal cords?', '["Cricoid cartilage", "Thyroid cartilage", "Arytenoid cartilage", "Tracheal cartilage"]'::jsonb, 1, 'The thyroid cartilage is the largest laryngeal cartilage and forms the visible laryngeal prominence.', 'Pre-Council', '🎓', true),
(5509, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The trachea bifurcates into the right and left main bronchi at a landmark called the:', '["Hilum", "Carina", "Larynx", "Cricoid ring"]'::jsonb, 1, 'The carina is the internal ridge at the tracheal bifurcation, a key landmark for confirming endotracheal tube position.', 'Pre-Council', '🎓', true),
(5510, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Why is a foreign body or misplaced endotracheal tube more likely to enter the right main bronchus than the left?', '["The right bronchus is longer and more horizontal", "The right bronchus is shorter, wider, and more vertical", "The left bronchus is obstructed by the heart", "The right lung has fewer lobes"]'::jsonb, 1, 'The right main bronchus is shorter, wider, and more vertically aligned with the trachea, making it the more common site for aspirated foreign bodies and inadvertent tube migration.', 'Pre-Council', '🎓', true),
(5511, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'How many lobes does the right lung have compared to the left lung?', '["Right 2, Left 3", "Right 3, Left 2", "Right 3, Left 3", "Right 2, Left 2"]'::jsonb, 1, 'The right lung has three lobes (upper, middle, lower); the left lung has two (upper, lower) to accommodate the cardiac notch.', 'Pre-Council', '🎓', true),
(5512, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The functional respiratory unit where gas exchange occurs is the:', '["Bronchiole", "Alveolus", "Trachea", "Larynx"]'::jsonb, 1, 'Alveoli are the terminal air sacs where oxygen and carbon dioxide are exchanged across a thin alveolar-capillary membrane.', 'Pre-Council', '🎓', true),
(5513, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which cells produce pulmonary surfactant?', '["Type I pneumocytes", "Type II pneumocytes", "Goblet cells", "Alveolar macrophages"]'::jsonb, 1, 'Type II pneumocytes synthesise and secrete surfactant, which reduces alveolar surface tension and prevents alveolar collapse.', 'Pre-Council', '🎓', true),
(5514, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The primary function of pulmonary surfactant is to:', '["Increase alveolar surface tension", "Reduce alveolar surface tension and prevent alveolar collapse", "Warm inhaled air", "Trap inhaled particles"]'::jsonb, 1, 'Surfactant lowers surface tension within alveoli, preventing atelectasis, especially in smaller alveoli that would otherwise collapse first (Laplace''s law).', 'Pre-Council', '🎓', true),
(5515, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which membrane covers the lungs and lines the thoracic cavity?', '["Peritoneum", "Pleura", "Pericardium", "Meninges"]'::jsonb, 1, 'The pleura consists of the visceral layer covering the lungs and the parietal layer lining the thoracic cavity.', 'Pre-Council', '🎓', true),
(5516, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The thin fluid-filled space between the visceral and parietal pleura is called the:', '["Mediastinum", "Pleural cavity", "Peritoneal cavity", "Pericardial space"]'::jsonb, 1, 'The pleural cavity contains a small amount of serous fluid that reduces friction during lung expansion and contraction.', 'Pre-Council', '🎓', true),
(5517, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Alveolar macrophages primarily function to:', '["Produce surfactant", "Phagocytose inhaled particles and pathogens", "Regulate blood pH", "Produce mucus"]'::jsonb, 1, 'Alveolar macrophages patrol the alveolar surface and phagocytose inhaled debris and microorganisms, an important innate defence mechanism.', 'Pre-Council', '🎓', true),
(5518, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The primary muscle of inspiration is the:', '["Internal intercostals", "Diaphragm", "Sternocleidomastoid", "Rectus abdominis"]'::jsonb, 1, 'The diaphragm contracts and flattens during quiet inspiration, increasing thoracic volume and drawing air into the lungs.', 'Pre-Council', '🎓', true),
(5519, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'During forced expiration, which muscle group becomes actively involved?', '["External intercostals", "Diaphragm only", "Internal intercostals and abdominal muscles", "Sternocleidomastoid"]'::jsonb, 2, 'Forced expiration recruits internal intercostal and abdominal muscles to actively decrease thoracic volume beyond passive elastic recoil.', 'Pre-Council', '🎓', true),
(5520, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which accessory muscles assist with inspiration during respiratory distress?', '["Diaphragm and external intercostals only", "Sternocleidomastoid and scalene muscles", "Internal intercostals only", "Abdominal muscles only"]'::jsonb, 1, 'The sternocleidomastoid and scalene muscles elevate the ribs and sternum to further increase thoracic volume when breathing effort increases.', 'Pre-Council', '🎓', true),
(5521, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The mucociliary escalator functions to:', '["Produce surfactant", "Trap and move debris/mucus upward and out of the airway", "Regulate airway diameter", "Warm inhaled air"]'::jsonb, 1, 'Cilia lining the respiratory tract beat rhythmically to move a mucus layer trapping particles upward toward the pharynx for clearance.', 'Pre-Council', '🎓', true),
(5522, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which structure prevents the trachea from collapsing during inspiration?', '["Smooth muscle", "C-shaped cartilage rings", "Epiglottis", "Cricoid cartilage alone"]'::jsonb, 1, 'C-shaped hyaline cartilage rings maintain tracheal patency while the open posterior aspect (against the oesophagus) allows for oesophageal expansion during swallowing.', 'Pre-Council', '🎓', true),
(5523, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The right lung differs from the left lung anatomically because it is:', '["Larger and has 3 lobes", "Smaller and has 2 lobes", "Equal in size with 3 lobes", "Larger with 2 lobes"]'::jsonb, 0, 'The right lung is larger with three lobes since the left lung is smaller to accommodate the cardiac notch and heart position.', 'Pre-Council', '🎓', true),
(5524, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The apex of each lung extends:', '["Above the clavicle into the root of the neck", "Below the diaphragm", "Into the mediastinum", "Below the 12th rib"]'::jsonb, 0, 'The apex of the lung rises above the clavicle, a fact relevant to risk of pneumothorax during subclavian line insertion.', 'Pre-Council', '🎓', true),
(5525, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The base of each lung rests upon the:', '["Heart", "Diaphragm", "Sternum", "Ribs"]'::jsonb, 1, 'The concave base of each lung sits directly on the diaphragm.', 'Pre-Council', '🎓', true),
(5526, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which respiratory tract structures are classified as ''conducting airways'' with no gas exchange function?', '["Alveoli and alveolar ducts", "Trachea, bronchi, and bronchioles (excluding respiratory bronchioles)", "Respiratory bronchioles only", "Alveolar sacs"]'::jsonb, 1, 'Conducting airways from the trachea through terminal bronchioles move air but do not participate in gas exchange, contributing to anatomical dead space.', 'Pre-Council', '🎓', true),
(5527, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The anatomical dead space refers to:', '["The volume of air in alveoli not perfused", "The volume of air in conducting airways that does not participate in gas exchange", "Collapsed alveoli", "Air trapped in the pleural space"]'::jsonb, 1, 'Anatomical dead space is the conducting airway volume (approximately 150 mL in an adult) where no gas exchange occurs.', 'Pre-Council', '🎓', true),
(5528, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The visceral pleura is innervated by:', '["Somatic pain fibres, making it pain-sensitive", "Autonomic fibres only, making it insensitive to pain", "No nerve supply", "Only the phrenic nerve"]'::jsonb, 1, 'The visceral pleura lacks somatic sensory innervation, so pain from pleural pathology typically originates from the parietal pleura.', 'Pre-Council', '🎓', true),
(5529, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Irritation of the parietal pleura classically causes pain that may be referred to which area, especially if the diaphragmatic pleura is involved?', '["The lower back", "The shoulder tip", "The lower abdomen", "The wrist"]'::jsonb, 1, 'Diaphragmatic pleural irritation can refer pain to the shoulder tip via the phrenic nerve (C3-C5 dermatomes).', 'Pre-Council', '🎓', true),
(5530, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which nerve primarily innervates the diaphragm?', '["Vagus nerve", "Phrenic nerve", "Intercostal nerves", "Recurrent laryngeal nerve"]'::jsonb, 1, 'The phrenic nerve, arising from cervical roots C3-C5, is the primary motor supply to the diaphragm (''C3, 4, 5 keeps the diaphragm alive'').', 'Pre-Council', '🎓', true),
(5531, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Damage to the recurrent laryngeal nerve during neck surgery most directly affects:', '["Diaphragm movement", "Vocal cord movement and voice", "Tracheal cartilage integrity", "Bronchial smooth muscle tone"]'::jsonb, 1, 'The recurrent laryngeal nerve innervates most intrinsic laryngeal muscles controlling the vocal cords; injury causes hoarseness or vocal cord paralysis.', 'Pre-Council', '🎓', true),
(5532, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The larynx is primarily composed of which type of tissue framework?', '["Bone", "Cartilage", "Smooth muscle only", "Fibrous connective tissue only"]'::jsonb, 1, 'The larynx''s structural framework consists of several cartilages (thyroid, cricoid, arytenoid, epiglottic) connected by ligaments and muscles.', 'Pre-Council', '🎓', true),
(5533, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which structure marks the division between the upper and lower respiratory tract?', '["The nasal cavity", "The larynx", "The bronchioles", "The alveoli"]'::jsonb, 1, 'The larynx is generally considered the anatomical boundary between the upper respiratory tract (above) and lower respiratory tract (below).', 'Pre-Council', '🎓', true),
(5534, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Bronchioles differ from bronchi structurally in that bronchioles:', '["Contain cartilage rings", "Lack cartilage and rely on smooth muscle for structural support", "Are lined by stratified squamous epithelium", "Have no smooth muscle"]'::jsonb, 1, 'Bronchioles lack cartilaginous support, so their diameter is regulated entirely by smooth muscle tone, making them the primary site of airway resistance changes (e.g. in asthma).', 'Pre-Council', '🎓', true),
(5535, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Goblet cells in the respiratory epithelium primarily function to:', '["Detect chemical irritants", "Secrete mucus", "Facilitate gas exchange", "Contract to narrow the airway"]'::jsonb, 1, 'Goblet cells secrete mucus that traps inhaled particles and pathogens, which the mucociliary escalator then clears.', 'Pre-Council', '🎓', true),
(5536, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The respiratory epithelium lining most of the conducting airway is classified as:', '["Simple squamous", "Pseudostratified ciliated columnar with goblet cells", "Stratified squamous", "Simple cuboidal"]'::jsonb, 1, 'Pseudostratified ciliated columnar epithelium lines most conducting airways, supporting mucus production and ciliary clearance.', 'Pre-Council', '🎓', true),
(5537, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The alveolar-capillary membrane is optimised for gas diffusion mainly because it is:', '["Thick and impermeable", "Extremely thin with a large surface area", "Composed of cartilage", "Poorly vascularised"]'::jsonb, 1, 'The alveolar-capillary membrane is only about 0.5 micrometres thick with an enormous total surface area (~70 m² in adults), maximising diffusion efficiency.', 'Pre-Council', '🎓', true),
(5538, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which structure connects adjacent alveoli and allows collateral ventilation?', '["Pores of Kohn", "Carina", "Bronchioles", "Pleura"]'::jsonb, 0, 'Pores of Kohn are small openings in alveolar walls that allow air to move between adjacent alveoli, providing collateral ventilation pathways.', 'Pre-Council', '🎓', true),
(5539, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The total number of alveoli in adult human lungs is approximately:', '["3 million", "30 million", "300 million", "3 billion"]'::jsonb, 2, 'Adult human lungs contain roughly 300-500 million alveoli, providing the large surface area needed for efficient gas exchange.', 'Pre-Council', '🎓', true),
(5540, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which lung zone receives the most ventilation and perfusion in an upright, spontaneously breathing person?', '["The apex", "The base", "The mid-zone equally with apex", "There is no regional difference"]'::jsonb, 1, 'Gravity causes greater blood flow and, to a lesser extent, greater ventilation at the lung bases in the upright position.', 'Pre-Council', '🎓', true),
(5541, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The mediastinum is the space located:', '["Within each lung", "Between the two lungs, containing the heart and great vessels", "Above the diaphragm only", "Within the pleural cavity"]'::jsonb, 1, 'The mediastinum is the central thoracic compartment between the two pleural cavities, containing the heart, great vessels, trachea, oesophagus, and other structures.', 'Pre-Council', '🎓', true),
(5542, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which respiratory structure is responsible for voice production?', '["Trachea", "Larynx (vocal cords)", "Pharynx", "Bronchi"]'::jsonb, 1, 'The vocal cords within the larynx vibrate as air passes through them, producing sound that is shaped into speech by the mouth and tongue.', 'Pre-Council', '🎓', true),
(5543, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The nasopharynx, oropharynx, and laryngopharynx together make up the:', '["Larynx", "Pharynx", "Trachea", "Nasal cavity"]'::jsonb, 1, 'The pharynx is a shared muscular passage for both air and food, divided into nasopharynx, oropharynx, and laryngopharynx.', 'Pre-Council', '🎓', true),
(5544, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Cilia in the respiratory tract beat in a coordinated direction primarily toward the:', '["Alveoli", "Pharynx, to be swallowed or expectorated", "Pleura", "Bronchioles"]'::jsonb, 1, 'Ciliary beating moves the mucus blanket upward toward the pharynx, where trapped debris is swallowed or coughed out.', 'Pre-Council', '🎓', true),
(5545, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Damage to cilia (e.g. from chronic smoking) primarily impairs which lung defence mechanism?', '["Gas exchange", "Mucociliary clearance", "Surfactant production", "Pleural fluid regulation"]'::jsonb, 1, 'Ciliary damage impairs the mucociliary escalator, allowing mucus and trapped pathogens to accumulate, increasing infection risk.', 'Pre-Council', '🎓', true),
(5546, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which of the following best describes the relationship between airway generation number and airway diameter as air moves from trachea to alveoli?', '["Diameter increases with each generation", "Diameter decreases with each generation, while total cross-sectional area increases", "Diameter and cross-sectional area both decrease", "Diameter remains constant"]'::jsonb, 1, 'Each individual airway becomes narrower with successive branching, but because branches multiply, total cross-sectional area increases dramatically toward the alveoli, slowing airflow velocity there.', 'Pre-Council', '🎓', true),
(5547, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The primary respiratory control centre is located in the:', '["Cerebral cortex", "Medulla oblongata", "Cerebellum", "Hypothalamus"]'::jsonb, 1, 'The medullary respiratory centre generates the basic rhythm of breathing and is the primary site of automatic respiratory control.', 'Pre-Council', '🎓', true),
(5548, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The pontine respiratory centres primarily function to:', '["Generate the basic breathing rhythm", "Fine-tune and smooth the breathing pattern set by the medulla", "Detect blood oxygen levels", "Control airway smooth muscle directly"]'::jsonb, 1, 'The pneumotaxic and apneustic centres in the pons modulate the medullary rhythm, helping to smooth the transition between inspiration and expiration.', 'Pre-Council', '🎓', true),
(5549, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The most potent physiological stimulus for increasing ventilation under normal conditions is:', '["Decreased arterial oxygen (PaO2)", "Increased arterial carbon dioxide (PaCO2)", "Increased blood pressure", "Decreased body temperature"]'::jsonb, 1, 'Central chemoreceptors are highly sensitive to changes in PaCO2 (via CSF pH), making CO2 the primary driver of minute ventilation in healthy individuals.', 'Pre-Council', '🎓', true),
(5550, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Central chemoreceptors that respond to changes in PaCO2 are located in the:', '["Carotid bodies", "Aortic arch", "Medulla oblongata", "Lung parenchyma"]'::jsonb, 2, 'Central chemoreceptors near the medulla respond to changes in cerebrospinal fluid pH, which reflects arterial PaCO2 levels.', 'Pre-Council', '🎓', true),
(5551, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Peripheral chemoreceptors located in the carotid and aortic bodies primarily respond to changes in:', '["PaCO2 only", "PaO2 (especially when significantly low), pH, and PaCO2", "Body temperature only", "Blood glucose"]'::jsonb, 1, 'Peripheral chemoreceptors are the main sensors of hypoxemia and also respond to pH and PaCO2 changes, though less sensitively than central chemoreceptors for CO2.', 'Pre-Council', '🎓', true),
(5552, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'In a patient with chronic CO2 retention (e.g. severe COPD), the primary driver of respiration may shift to:', '["Increased PaCO2", "Hypoxic drive (low PaO2)", "Increased blood pressure", "Body temperature"]'::jsonb, 1, 'With chronic hypercapnia, central chemoreceptors become less sensitive to CO2 over time, so hypoxaemia via peripheral chemoreceptors becomes the dominant ventilatory drive — the rationale for cautious oxygen titration in some COPD patients.', 'Pre-Council', '🎓', true),
(5553, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The Hering-Breuer reflex primarily functions to:', '["Increase respiratory rate during exercise", "Prevent lung over-inflation by inhibiting further inspiration when the lungs are already stretched", "Stimulate coughing", "Control heart rate"]'::jsonb, 1, 'Stretch receptors in the airway smooth muscle trigger the Hering-Breuer inflation reflex, preventing excessive lung inflation by inhibiting further inspiratory effort.', 'Pre-Council', '🎓', true),
(5554, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which of the following best describes eupnoea?', '["Absence of breathing", "Normal, quiet breathing", "Rapid, shallow breathing", "Difficult or laboured breathing"]'::jsonb, 1, 'Eupnoea refers to normal, comfortable breathing at rest.', 'Pre-Council', '🎓', true),
(5555, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Apnoea is defined as:', '["Rapid breathing", "Temporary cessation of breathing", "Slow breathing", "Laboured breathing"]'::jsonb, 1, 'Apnoea is a temporary cessation of spontaneous breathing.', 'Pre-Council', '🎓', true),
(5556, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Dyspnoea refers to:', '["Absence of breathing", "The subjective sensation of difficult or laboured breathing", "Abnormally slow breathing", "Rapid shallow breathing only"]'::jsonb, 1, 'Dyspnoea is the subjective experience of breathlessness or difficulty breathing, which may or may not correlate with objective measures of respiratory function.', 'Pre-Council', '🎓', true),
(5557, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Tachypnoea is best defined as:', '["Abnormally slow respiratory rate", "Abnormally rapid respiratory rate", "Absence of breathing", "Deep, laboured breathing"]'::jsonb, 1, 'Tachypnoea refers to an increased respiratory rate above the normal range for age.', 'Pre-Council', '🎓', true),
(5558, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Bradypnoea refers to:', '["Abnormally rapid breathing", "Abnormally slow respiratory rate", "Cessation of breathing", "Noisy breathing"]'::jsonb, 1, 'Bradypnoea is an abnormally slow respiratory rate.', 'Pre-Council', '🎓', true),
(5559, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Hyperventilation typically results in which acid-base disturbance?', '["Respiratory acidosis", "Respiratory alkalosis", "Metabolic acidosis", "Metabolic alkalosis"]'::jsonb, 1, 'Excessive ventilation blows off CO2 faster than it is produced, lowering PaCO2 and raising blood pH, causing respiratory alkalosis.', 'Pre-Council', '🎓', true),
(5560, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Hypoventilation typically leads to which acid-base disturbance?', '["Respiratory alkalosis", "Respiratory acidosis", "Metabolic alkalosis", "Metabolic acidosis"]'::jsonb, 1, 'Inadequate ventilation causes CO2 retention, lowering blood pH and causing respiratory acidosis.', 'Pre-Council', '🎓', true),
(5561, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Cheyne-Stokes respiration is characterised by:', '["Consistent deep breathing with no variation", "A crescendo-decrescendo pattern of breathing with periods of apnoea", "Rapid shallow breathing only", "Slow, regular breathing"]'::jsonb, 1, 'Cheyne-Stokes respiration cycles between deep, rapid breathing and apnoea, often seen in severe heart failure or brainstem injury.', 'Pre-Council', '🎓', true),
(5562, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Kussmaul breathing — deep, rapid, laboured respirations — is classically associated with:', '["Respiratory alkalosis", "Metabolic acidosis (e.g. diabetic ketoacidosis)", "Metabolic alkalosis", "Normal exercise"]'::jsonb, 1, 'Kussmaul breathing is a compensatory response to severe metabolic acidosis, attempting to blow off CO2 and raise blood pH.', 'Pre-Council', '🎓', true),
(5563, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Biot''s respiration (ataxic breathing) is most associated with damage to the:', '["Peripheral nerves", "Medulla oblongata", "Diaphragm muscle fibres", "Larynx"]'::jsonb, 1, 'Biot''s respiration — irregular breathing with periods of apnoea — reflects damage to the medullary respiratory centre, often from raised intracranial pressure or brainstem injury.', 'Pre-Council', '🎓', true),
(5564, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which term describes breathing that is difficult or uncomfortable only when lying flat?', '["Eupnoea", "Orthopnoea", "Apnoea", "Tachypnoea"]'::jsonb, 1, 'Orthopnoea is dyspnoea that occurs or worsens in the supine position, classically relieved by sitting upright, and is a key symptom of left heart failure.', 'Pre-Council', '🎓', true),
(5565, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Paroxysmal nocturnal dyspnoea refers to:', '["Breathlessness that occurs suddenly during sleep, waking the patient", "Difficulty breathing only during exercise", "Chronic daytime breathlessness", "Breathing difficulty only when standing"]'::jsonb, 0, 'Paroxysmal nocturnal dyspnoea is sudden breathlessness that wakes a sleeping patient, typically due to redistribution of fluid and worsening pulmonary congestion in heart failure.', 'Pre-Council', '🎓', true),
(5566, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which reflex is responsible for the cough response?', '["Hering-Breuer reflex", "Cough reflex, triggered by irritant receptors in the airway", "Baroreceptor reflex", "Stretch reflex of the diaphragm"]'::jsonb, 1, 'Irritant receptors in the airway epithelium detect mechanical or chemical stimuli and trigger the coordinated cough reflex to expel irritants.', 'Pre-Council', '🎓', true),
(5567, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The primary function of the respiratory centre''s rhythm generation is to produce:', '["Voluntary control of breathing only", "The automatic, involuntary rhythm of breathing", "Emotional responses", "Speech production only"]'::jsonb, 1, 'The medullary respiratory centres generate the automatic, rhythmic pattern of inspiration and expiration without conscious effort.', 'Pre-Council', '🎓', true),
(5568, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Voluntary control of breathing (e.g. holding one''s breath) originates in the:', '["Medulla oblongata", "Cerebral cortex", "Pons only", "Spinal cord"]'::jsonb, 1, 'The cerebral cortex allows voluntary override of the automatic breathing pattern, though this is ultimately limited by rising PaCO2 and falling PaO2.', 'Pre-Council', '🎓', true),
(5569, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Stretch receptors involved in the Hering-Breuer reflex are located primarily in the:', '["Alveoli", "Airway smooth muscle", "Carotid bodies", "Aortic arch"]'::jsonb, 1, 'Pulmonary stretch receptors in the smooth muscle of the airways detect lung inflation and signal the brainstem to inhibit further inspiration.', 'Pre-Council', '🎓', true),
(5570, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'J-receptors (juxtacapillary receptors) in the lung respond primarily to:', '["Airway stretch", "Pulmonary capillary congestion and interstitial oedema", "Blood glucose levels", "Body temperature"]'::jsonb, 1, 'J-receptors near the pulmonary capillaries are stimulated by interstitial oedema, congestion, or microemboli, contributing to the sensation of dyspnoea in conditions like pulmonary oedema.', 'Pre-Council', '🎓', true),
(5571, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which factor most directly increases the rate and depth of breathing during moderate exercise?', '["Decreased body temperature", "Increased CO2 production and metabolic demand", "Decreased blood pressure", "Decreased cardiac output"]'::jsonb, 1, 'Increased metabolic CO2 production during exercise is a major stimulus for increased ventilation, working alongside neural and other chemical factors.', 'Pre-Council', '🎓', true),
(5572, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Intrapleural pressure is normally:', '["Equal to atmospheric pressure", "Negative relative to atmospheric pressure", "Positive relative to atmospheric pressure", "Highly variable with no consistent pattern"]'::jsonb, 1, 'Negative intrapleural pressure (about -4 to -8 cmH2O) keeps the lungs expanded against the chest wall''s tendency to spring outward and the lung''s tendency to collapse inward.', 'Pre-Council', '🎓', true),
(5573, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'If air enters the pleural space (pneumothorax), the immediate physiological consequence is:', '["Increased lung expansion", "Loss of negative intrapleural pressure, allowing lung collapse", "Improved gas exchange", "No effect on lung volume"]'::jsonb, 1, 'Air in the pleural space eliminates the negative pressure gradient that keeps the lung expanded, allowing elastic recoil to collapse the lung.', 'Pre-Council', '🎓', true),
(5574, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Compliance of the lung refers to:', '["The resistance to airflow", "The ease with which the lung expands for a given change in pressure", "The rate of gas diffusion", "The total lung capacity"]'::jsonb, 1, 'Lung compliance describes distensibility — how much the lung volume changes per unit change in pressure; low compliance (stiff lungs) means more pressure is needed to achieve the same volume change.', 'Pre-Council', '🎓', true),
(5575, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A condition that decreases lung compliance (makes the lung ''stiffer'') is:', '["Emphysema", "Pulmonary fibrosis", "Normal ageing alone", "Asthma"]'::jsonb, 1, 'Pulmonary fibrosis causes scarring and stiffening of lung tissue, decreasing compliance and increasing the work of breathing.', 'Pre-Council', '🎓', true),
(5576, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Emphysema typically causes lung compliance to:', '["Decrease", "Increase, due to loss of elastic recoil", "Remain unchanged", "Fluctuate randomly"]'::jsonb, 1, 'Destruction of alveolar walls and elastic tissue in emphysema increases lung compliance but reduces elastic recoil, contributing to air trapping.', 'Pre-Council', '🎓', true),
(5577, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Airway resistance is primarily determined by:', '["Lung compliance", "The radius of the airway", "Surfactant production", "Alveolar surface area"]'::jsonb, 1, 'Airway resistance is inversely related to the fourth power of airway radius (Poiseuille''s law), so small changes in airway diameter (e.g. bronchoconstriction) markedly affect resistance.', 'Pre-Council', '🎓', true),
(5578, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Bronchoconstriction, as seen in an asthma attack, primarily affects respiratory mechanics by:', '["Decreasing airway resistance", "Increasing airway resistance and work of breathing", "Increasing lung compliance", "Having no effect on airflow"]'::jsonb, 1, 'Narrowed airway diameter during bronchoconstriction sharply increases resistance to airflow, increasing the work required to breathe.', 'Pre-Council', '🎓', true),
(5579, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The work of breathing is increased by all of the following EXCEPT:', '["Decreased lung compliance", "Increased airway resistance", "Normal surfactant function", "Obesity restricting chest wall movement"]'::jsonb, 2, 'Normal surfactant function reduces surface tension and the work of breathing; its absence (as in ARDS or prematurity) increases work of breathing.', 'Pre-Council', '🎓', true),
(5580, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which nervous system division primarily causes bronchodilation?', '["Parasympathetic (via acetylcholine)", "Sympathetic (via epinephrine acting on beta-2 receptors)", "Somatic nervous system", "Enteric nervous system"]'::jsonb, 1, 'Sympathetic stimulation, particularly via beta-2 adrenergic receptors, causes bronchial smooth muscle relaxation and bronchodilation — the rationale for beta-2 agonist bronchodilator therapy.', 'Pre-Council', '🎓', true),
(5581, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which nervous system division primarily causes bronchoconstriction?', '["Sympathetic nervous system", "Parasympathetic nervous system (via acetylcholine on muscarinic receptors)", "Somatic nervous system", "Central nervous system directly"]'::jsonb, 1, 'Parasympathetic (vagal) stimulation releases acetylcholine acting on muscarinic receptors in bronchial smooth muscle, causing bronchoconstriction.', 'Pre-Council', '🎓', true),
(5582, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The Bohr effect describes how:', '["Oxygen affects CO2 transport", "Decreased pH (increased CO2/acidity) reduces haemoglobin''s affinity for oxygen, promoting O2 release to tissues", "Temperature has no effect on oxygen binding", "CO2 is transported dissolved in plasma only"]'::jsonb, 1, 'The Bohr effect explains how a more acidic, CO2-rich environment (as in metabolically active tissue) shifts the oxyhaemoglobin dissociation curve right, promoting oxygen release where it''s needed most.', 'Pre-Council', '🎓', true),
(5583, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The Haldane effect describes how:', '["Oxygenated haemoglobin has a reduced capacity to carry CO2, promoting CO2 release in the lungs", "Deoxygenated blood carries less CO2", "Oxygen binding is unaffected by CO2 levels", "CO2 only affects the kidneys"]'::jsonb, 0, 'The Haldane effect describes how oxygenation of haemoglobin in the lungs reduces its affinity for CO2, facilitating CO2 unloading and exhalation.', 'Pre-Council', '🎓', true),
(5584, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'At high altitude, decreased atmospheric pressure primarily affects respiration by:', '["Increasing the percentage of oxygen in air", "Decreasing the partial pressure of oxygen available for diffusion", "Increasing airway resistance", "Increasing lung compliance"]'::jsonb, 1, 'Although the percentage of oxygen in air (21%) remains constant, the lower total atmospheric pressure at altitude reduces the partial pressure of oxygen, impairing diffusion into blood.', 'Pre-Council', '🎓', true),
(5585, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Physiological compensation for chronic high-altitude exposure includes:', '["Decreased red blood cell production", "Increased erythropoietin and red blood cell production", "Decreased minute ventilation", "Decreased 2,3-DPG"]'::jsonb, 1, 'Chronic hypoxia at altitude stimulates erythropoietin release, increasing red blood cell mass to improve oxygen-carrying capacity.', 'Pre-Council', '🎓', true),
(5586, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Exercise increases ventilation primarily through:', '["Decreased CO2 production", "Increased CO2 production, metabolic demand, and neural stimulation", "Decreased body temperature", "Decreased cardiac output"]'::jsonb, 1, 'Exercise increases metabolic CO2 production and neural/chemical drive to ventilation, matching gas exchange to increased metabolic demand.', 'Pre-Council', '🎓', true),
(5587, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Fever/increased body temperature typically has which effect on respiratory rate?', '["Decreases it", "Increases it, due to increased metabolic rate", "Has no effect", "Causes apnoea"]'::jsonb, 1, 'Elevated body temperature increases metabolic rate and CO2 production, stimulating an increase in respiratory rate.', 'Pre-Council', '🎓', true),
(5588, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which class of drugs can significantly depress the respiratory centre and reduce respiratory rate?', '["Beta-2 agonists", "Opioids", "Diuretics", "Antibiotics"]'::jsonb, 1, 'Opioids directly depress the medullary respiratory centre''s sensitivity to CO2, reducing respiratory drive and rate, a major risk of overdose.', 'Pre-Council', '🎓', true),
(5589, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Metabolic acidosis typically triggers which respiratory compensatory response?', '["Hypoventilation", "Hyperventilation, to blow off CO2 and raise pH", "No respiratory change", "Bronchoconstriction"]'::jsonb, 1, 'The respiratory system compensates for metabolic acidosis by increasing ventilation to reduce PaCO2, helping to normalise blood pH (Kussmaul breathing in severe cases).', 'Pre-Council', '🎓', true),
(5590, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Anxiety and pain commonly cause which respiratory pattern change?', '["Bradypnoea", "Hyperventilation/tachypnoea", "Apnoea", "No change in respiratory rate"]'::jsonb, 1, 'Anxiety and pain activate sympathetic responses and central mechanisms that increase respiratory rate, sometimes leading to hyperventilation.', 'Pre-Council', '🎓', true),
(5591, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Obesity affects respiratory mechanics primarily by:', '["Increasing lung compliance", "Restricting chest wall movement and reducing functional residual capacity", "Increasing airway diameter", "Having no significant effect"]'::jsonb, 1, 'Excess adipose tissue restricts chest wall and diaphragmatic movement, reducing lung volumes (particularly FRC) and increasing the work of breathing.', 'Pre-Council', '🎓', true),
(5592, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Pregnancy affects maternal respiratory physiology by causing:', '["Decreased minute ventilation", "Increased minute ventilation, partly due to progesterone''s effect on the respiratory centre", "Decreased oxygen consumption", "Increased residual volume"]'::jsonb, 1, 'Progesterone increases the sensitivity of the respiratory centre to CO2, increasing minute ventilation during pregnancy, partly to support increased maternal and fetal oxygen demand.', 'Pre-Council', '🎓', true),
(5593, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Sleep typically has which effect on respiratory drive compared to wakefulness?', '["Increases respiratory drive", "Slightly decreases respiratory drive and responsiveness to CO2/O2 changes", "Has no effect", "Causes hyperventilation"]'::jsonb, 1, 'During sleep, especially REM sleep, chemoreceptor sensitivity and respiratory drive are somewhat reduced compared to wakefulness.', 'Pre-Council', '🎓', true),
(5594, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which condition, characterised by repeated upper airway collapse during sleep, disrupts normal breathing patterns and gas exchange?', '["Central sleep apnoea only", "Obstructive sleep apnoea", "Cheyne-Stokes respiration only", "Kussmaul breathing"]'::jsonb, 1, 'Obstructive sleep apnoea involves repeated partial or complete upper airway collapse during sleep, causing intermittent hypoxia and disrupted sleep architecture.', 'Pre-Council', '🎓', true),
(5595, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Anaemia affects respiration primarily by reducing:', '["The partial pressure of oxygen in inspired air", "The blood''s oxygen-carrying capacity due to reduced haemoglobin", "Airway diameter", "Lung compliance"]'::jsonb, 1, 'Anaemia reduces haemoglobin concentration, decreasing the oxygen-carrying capacity of blood even though PaO2 may remain normal, often triggering compensatory tachypnoea and tachycardia.', 'Pre-Council', '🎓', true),
(5596, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Carbon monoxide poisoning impairs oxygen delivery primarily by:', '["Damaging the alveoli directly", "Binding haemoglobin with much greater affinity than oxygen, displacing it", "Increasing red blood cell production acutely", "Causing bronchoconstriction only"]'::jsonb, 1, 'Carbon monoxide binds haemoglobin roughly 200 times more strongly than oxygen, forming carboxyhaemoglobin and severely reducing effective oxygen transport despite normal PaO2 readings.', 'Pre-Council', '🎓', true),
(5597, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Cigarette smoking affects respiratory function by causing all of the following EXCEPT:', '["Ciliary damage and impaired mucociliary clearance", "Chronic airway inflammation", "Increased surfactant production", "Increased mucus production"]'::jsonb, 2, 'Smoking damages lung tissue and impairs, rather than increases, normal protective mechanisms; it does not enhance surfactant production.', 'Pre-Council', '🎓', true),
(5598, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Restrictive lung disease is characterised primarily by:', '["Increased airway resistance with normal lung volumes", "Reduced lung volumes due to decreased compliance or expansion capacity", "Increased total lung capacity", "Normal FEV1/FVC ratio with reduced total capacity is not typical"]'::jsonb, 1, 'Restrictive diseases (e.g. pulmonary fibrosis) reduce lung volumes because the lung or chest wall cannot expand normally, typically preserving or increasing the FEV1/FVC ratio.', 'Pre-Council', '🎓', true),
(5599, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Obstructive lung disease is characterised primarily by:', '["Reduced lung volumes with normal airflow", "Increased airway resistance causing difficulty with expiration", "Increased FEV1/FVC ratio", "Normal residual volume in all cases"]'::jsonb, 1, 'Obstructive diseases (e.g. asthma, COPD) increase airway resistance, particularly affecting expiratory airflow, and typically reduce the FEV1/FVC ratio.', 'Pre-Council', '🎓', true),
(5600, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Cold air exposure can trigger bronchoconstriction most notably in patients with:', '["Healthy lungs only", "Asthma or reactive airway disease", "Restrictive lung disease only", "No respiratory condition"]'::jsonb, 1, 'Cold, dry air is a common trigger for bronchospasm in individuals with hyperreactive airways, such as those with asthma.', 'Pre-Council', '🎓', true),
(5601, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Air pollution and particulate matter primarily affect respiratory health by:', '["Improving mucociliary clearance", "Causing airway inflammation and impaired gas exchange over time", "Having no measurable effect", "Increasing lung compliance"]'::jsonb, 1, 'Chronic exposure to air pollutants causes airway inflammation, oxidative stress, and can worsen or contribute to chronic respiratory disease.', 'Pre-Council', '🎓', true),
(5602, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Positioning a patient with unilateral lung disease with the good lung dependent (down) generally aims to:', '["Worsen ventilation-perfusion matching", "Optimise perfusion to the better-ventilated lung, improving overall gas exchange", "Increase airway resistance", "Have no clinical effect"]'::jsonb, 1, 'In unilateral lung disease, positioning the healthier lung dependent takes advantage of gravity-driven perfusion to the better-functioning lung, improving overall V/Q matching ("good lung down").', 'Pre-Council', '🎓', true),
(5603, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Gas exchange in the alveoli occurs primarily by the process of:', '["Active transport", "Simple diffusion, driven by partial pressure gradients", "Osmosis", "Facilitated transport requiring ATP"]'::jsonb, 1, 'Oxygen and carbon dioxide move across the alveolar-capillary membrane by simple diffusion, moving from areas of higher to lower partial pressure.', 'Pre-Council', '🎓', true),
(5604, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The partial pressure of oxygen in atmospheric air at sea level is approximately:', '["21 mmHg", "100 mmHg", "160 mmHg", "760 mmHg"]'::jsonb, 2, 'Atmospheric PO2 at sea level is approximately 160 mmHg (21% of 760 mmHg total atmospheric pressure).', 'Pre-Council', '🎓', true),
(5605, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Normal arterial partial pressure of oxygen (PaO2) in a healthy adult breathing room air is approximately:', '["40-45 mmHg", "60-65 mmHg", "80-100 mmHg", "120-140 mmHg"]'::jsonb, 2, 'Normal PaO2 in a healthy adult on room air is typically 80-100 mmHg, though this declines somewhat with age.', 'Pre-Council', '🎓', true),
(5606, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Normal arterial partial pressure of carbon dioxide (PaCO2) is approximately:', '["15-20 mmHg", "35-45 mmHg", "60-70 mmHg", "90-100 mmHg"]'::jsonb, 1, 'Normal PaCO2 is 35-45 mmHg; values outside this range indicate hyperventilation (low) or hypoventilation (high).', 'Pre-Council', '🎓', true),
(5607, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'According to Fick''s law of diffusion, gas exchange across the alveolar membrane is enhanced by:', '["A thicker membrane", "A larger surface area and shorter diffusion distance", "Reduced partial pressure gradient", "Decreased membrane permeability"]'::jsonb, 1, 'Fick''s law states diffusion rate is proportional to surface area and the partial pressure gradient, and inversely proportional to membrane thickness — so a large, thin membrane maximises gas exchange.', 'Pre-Council', '🎓', true),
(5608, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which condition impairs gas exchange by increasing the diffusion distance across the alveolar-capillary membrane?', '["Pulmonary fibrosis", "Bronchoconstriction", "Anaemia", "Increased cardiac output"]'::jsonb, 0, 'Pulmonary fibrosis thickens and scars the alveolar-capillary interface, increasing diffusion distance and impairing gas exchange, particularly for oxygen.', 'Pre-Council', '🎓', true),
(5609, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Oxygen is transported in the blood mainly:', '["Dissolved in plasma", "Bound to haemoglobin", "Bound to plasma proteins other than haemoglobin", "As bicarbonate"]'::jsonb, 1, 'The majority (about 98%) of oxygen in blood is carried bound to haemoglobin, with only a small fraction dissolved in plasma.', 'Pre-Council', '🎓', true),
(5610, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The majority of carbon dioxide in blood is transported as:', '["Dissolved CO2 in plasma", "Bicarbonate ions (HCO3-)", "Carbaminohaemoglobin", "Carbonic acid"]'::jsonb, 1, 'Approximately 70% of CO2 is transported as bicarbonate ions, formed via the reaction of CO2 with water catalysed by carbonic anhydrase, mostly within red blood cells.', 'Pre-Council', '🎓', true),
(5611, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The enzyme carbonic anhydrase, found in red blood cells, catalyses the reaction between:', '["Oxygen and haemoglobin", "CO2 and water to form carbonic acid", "Glucose and oxygen", "Bicarbonate and chloride only"]'::jsonb, 1, 'Carbonic anhydrase rapidly catalyses CO2 + H2O to carbonic acid (H2CO3), which dissociates into H+ and HCO3-, the main mechanism of CO2 transport.', 'Pre-Council', '🎓', true),
(5612, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The chloride shift refers to the exchange of chloride for which ion across the red blood cell membrane?', '["Sodium", "Bicarbonate", "Potassium", "Calcium"]'::jsonb, 1, 'As bicarbonate is generated within red blood cells and diffuses into plasma, chloride ions move into the cell to maintain electrical neutrality — the chloride (Hamburger) shift.', 'Pre-Council', '🎓', true),
(5613, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'An oxyhaemoglobin saturation of 90% roughly corresponds to a PaO2 of approximately:', '["40 mmHg", "60 mmHg", "80 mmHg", "100 mmHg"]'::jsonb, 1, 'On the oxyhaemoglobin dissociation curve, an SaO2 of 90% corresponds to a PaO2 of about 60 mmHg — the steep part of the curve where small PaO2 drops cause larger saturation drops.', 'Pre-Council', '🎓', true),
(5614, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A rightward shift of the oxyhaemoglobin dissociation curve indicates:', '["Increased haemoglobin affinity for oxygen", "Decreased haemoglobin affinity for oxygen, favouring oxygen release to tissues", "No change in oxygen binding", "Increased CO2 binding to haemoglobin only"]'::jsonb, 1, 'A rightward shift (caused by increased temperature, PaCO2, acidity, or 2,3-DPG) reduces haemoglobin''s affinity for oxygen, promoting oxygen unloading at the tissue level.', 'Pre-Council', '🎓', true),
(5615, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which of the following causes a leftward shift of the oxyhaemoglobin dissociation curve (increased affinity for oxygen)?', '["Increased temperature", "Decreased pH (acidosis)", "Decreased temperature, decreased 2,3-DPG, and alkalosis", "Increased 2,3-DPG"]'::jsonb, 2, 'Decreased temperature, decreased 2,3-DPG, and alkalosis all shift the curve left, increasing haemoglobin''s affinity for oxygen but reducing oxygen release to tissues.', 'Pre-Council', '🎓', true),
(5616, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', '2,3-diphosphoglycerate (2,3-DPG) in red blood cells functions to:', '["Increase haemoglobin''s affinity for oxygen", "Decrease haemoglobin''s affinity for oxygen, facilitating tissue oxygen delivery", "Transport CO2 exclusively", "Buffer blood pH directly"]'::jsonb, 1, '2,3-DPG binds haemoglobin and reduces its oxygen affinity, shifting the curve right and promoting oxygen release to tissues, particularly important in chronic hypoxic states.', 'Pre-Council', '🎓', true),
(5617, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Ventilation-perfusion (V/Q) matching is optimal when:', '["Ventilation and perfusion are both zero in a lung region", "Ventilation and blood flow to a lung region are well matched", "Ventilation greatly exceeds perfusion", "Perfusion greatly exceeds ventilation"]'::jsonb, 1, 'Efficient gas exchange requires ventilated alveoli to be matched with adequate blood flow (perfusion); mismatches in either direction impair gas exchange.', 'Pre-Council', '🎓', true),
(5618, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A pulmonary embolism causes which type of V/Q mismatch?', '["Low V/Q (shunt-like, perfusion without ventilation)", "High V/Q (dead-space-like, ventilation without perfusion)", "No mismatch occurs", "Equal V and Q"]'::jsonb, 1, 'A pulmonary embolism obstructs blood flow to ventilated alveoli, creating a high V/Q ratio (increased physiological dead space) since those areas are ventilated but not perfused.', 'Pre-Council', '🎓', true),
(5619, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Airway obstruction or alveolar collapse (atelectasis) typically causes which V/Q abnormality?', '["High V/Q (dead space)", "Low V/Q or shunt (perfusion without adequate ventilation)", "Perfectly matched V/Q", "No effect on gas exchange"]'::jsonb, 1, 'When alveoli are poorly ventilated but still perfused (as in atelectasis), blood passes through without adequate oxygenation, creating a shunt-like low V/Q state.', 'Pre-Council', '🎓', true),
(5620, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A true intrapulmonary shunt refers to blood that:', '["Passes through well-ventilated alveoli", "Passes through the lungs without being exposed to any ventilated alveoli", "Bypasses the lungs entirely via extracardiac vessels", "Is completely oxygenated"]'::jsonb, 1, 'A true shunt occurs when blood perfuses completely unventilated alveoli (e.g. filled with fluid or completely collapsed), so it returns to systemic circulation without being oxygenated at all.', 'Pre-Council', '🎓', true),
(5621, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Hypoxic pulmonary vasoconstriction is a physiological mechanism that:', '["Increases blood flow to poorly ventilated lung regions", "Redirects blood flow away from poorly ventilated alveoli toward better-ventilated areas", "Has no effect on V/Q matching", "Only occurs in the systemic circulation"]'::jsonb, 1, 'Hypoxic pulmonary vasoconstriction is a protective reflex that reduces blood flow to poorly ventilated alveolar regions, optimising overall V/Q matching — though it can cause pulmonary hypertension if widespread and chronic.', 'Pre-Council', '🎓', true),
(5622, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The alveolar-arterial (A-a) oxygen gradient is used clinically to:', '["Measure lung compliance", "Assess the efficiency of oxygen transfer from alveoli to blood", "Measure airway resistance", "Determine haemoglobin concentration"]'::jsonb, 1, 'The A-a gradient compares calculated alveolar oxygen to measured arterial oxygen; a widened gradient suggests impaired gas exchange, such as V/Q mismatch, shunt, or diffusion impairment.', 'Pre-Council', '🎓', true),
(5623, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'An increased A-a gradient with hypoxaemia that fails to correct significantly with supplemental oxygen suggests:', '["Simple hypoventilation", "A significant intrapulmonary shunt", "Normal lung function", "Anaemia alone"]'::jsonb, 1, 'A true shunt (blood bypassing ventilated alveoli entirely) responds poorly to supplemental oxygen, since the shunted blood never contacts oxygen-enriched alveolar gas — a key diagnostic clue distinguishing shunt from other causes of hypoxaemia.', 'Pre-Council', '🎓', true),
(5624, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Diffusion limitation as a cause of hypoxaemia becomes more clinically significant during:', '["Rest in a healthy individual", "Strenuous exercise or conditions with a thickened alveolar-capillary membrane", "Sleep in a healthy individual", "Breath-holding only"]'::jsonb, 1, 'Normally there''s ample time for full gas equilibration; but with a thickened membrane (e.g. fibrosis) or shortened transit time (e.g. exercise), diffusion may not be complete, causing hypoxaemia.', 'Pre-Council', '🎓', true),
(5625, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Tidal volume (TV) is defined as:', '["The maximum volume that can be inhaled after normal inspiration", "The volume of air moved in or out of the lungs during normal quiet breathing", "The volume remaining in the lungs after maximal expiration", "The total volume of the lungs"]'::jsonb, 1, 'Tidal volume is the amount of air inhaled or exhaled during a single normal breath, typically about 500 mL in an average adult.', 'Pre-Council', '🎓', true),
(5626, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'The normal adult resting tidal volume is approximately:', '["150 mL", "500 mL", "1200 mL", "3000 mL"]'::jsonb, 1, 'Average resting tidal volume in adults is approximately 500 mL, though it varies with body size.', 'Pre-Council', '🎓', true),
(5627, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Inspiratory reserve volume (IRV) is defined as:', '["Air that can be forcefully exhaled after normal expiration", "The additional air that can be forcefully inhaled after a normal tidal inspiration", "Air remaining in the lungs after maximal expiration", "Total lung capacity minus vital capacity"]'::jsonb, 1, 'IRV is the extra volume that can be inhaled beyond a normal tidal breath, using maximum inspiratory effort.', 'Pre-Council', '🎓', true),
(5628, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Expiratory reserve volume (ERV) is defined as:', '["The additional air that can be forcefully exhaled after a normal tidal expiration", "Air inhaled beyond normal tidal volume", "The total capacity of the lungs", "Air that cannot be measured by spirometry"]'::jsonb, 0, 'ERV is the extra volume that can be forcefully exhaled after a normal tidal breath, beyond passive resting expiration.', 'Pre-Council', '🎓', true),
(5629, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Residual volume (RV) is defined as:', '["The volume exhaled during a normal breath", "The volume of air remaining in the lungs after maximal forced expiration", "The maximum volume the lungs can hold", "The volume inhaled during a maximal inspiration"]'::jsonb, 1, 'Residual volume is the air that always remains in the lungs even after the most forceful expiration, preventing alveolar collapse; it cannot be measured directly by spirometry.', 'Pre-Council', '🎓', true),
(5630, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which lung volume cannot be measured directly by simple spirometry and requires methods like helium dilution or body plethysmography?', '["Tidal volume", "Inspiratory reserve volume", "Expiratory reserve volume", "Residual volume"]'::jsonb, 3, 'Because residual volume (and any capacity that includes it, like FRC and TLC) cannot be exhaled, it requires indirect measurement techniques such as helium dilution, nitrogen washout, or body plethysmography.', 'Pre-Council', '🎓', true),
(5631, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Vital capacity (VC) is defined as:', '["Tidal volume plus residual volume", "The maximum volume of air that can be exhaled after a maximal inspiration", "Residual volume alone", "The volume of dead space"]'::jsonb, 1, 'Vital capacity is the total volume that can be voluntarily moved in and out of the lungs — the sum of IRV, TV, and ERV.', 'Pre-Council', '🎓', true),
(5632, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Vital capacity is calculated as the sum of:', '["IRV + TV + ERV", "TV + RV only", "IRV + RV", "ERV + RV"]'::jsonb, 0, 'Vital capacity equals inspiratory reserve volume plus tidal volume plus expiratory reserve volume — everything except residual volume.', 'Pre-Council', '🎓', true),
(5633, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Total lung capacity (TLC) is defined as:', '["Vital capacity minus residual volume", "The sum of vital capacity and residual volume", "Tidal volume alone", "Functional residual capacity alone"]'::jsonb, 1, 'Total lung capacity is the maximum volume the lungs can hold, equal to vital capacity plus residual volume.', 'Pre-Council', '🎓', true),
(5634, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Functional residual capacity (FRC) is defined as:', '["The volume of air in the lungs at the end of a normal, passive expiration", "The volume inhaled during maximal inspiration", "Tidal volume alone", "Vital capacity minus tidal volume"]'::jsonb, 0, 'FRC is the volume remaining in the lungs after a normal tidal expiration, equal to expiratory reserve volume plus residual volume, and represents the lung''s resting equilibrium volume.', 'Pre-Council', '🎓', true),
(5635, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Functional residual capacity is calculated as:', '["ERV + RV", "IRV + TV", "TV + RV", "IRV + ERV"]'::jsonb, 0, 'FRC equals expiratory reserve volume plus residual volume.', 'Pre-Council', '🎓', true),
(5636, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Inspiratory capacity (IC) is defined as:', '["The maximum air that can be inhaled starting from the resting expiratory level", "Air remaining after maximal expiration", "Vital capacity minus residual volume", "Tidal volume alone"]'::jsonb, 0, 'Inspiratory capacity is the maximum amount of air that can be inhaled after a normal tidal expiration, equal to tidal volume plus inspiratory reserve volume.', 'Pre-Council', '🎓', true),
(5637, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Inspiratory capacity is calculated as:', '["TV + IRV", "TV + ERV", "IRV + ERV", "TLC - VC"]'::jsonb, 0, 'Inspiratory capacity equals tidal volume plus inspiratory reserve volume.', 'Pre-Council', '🎓', true),
(5638, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A normal adult''s total lung capacity is approximately:', '["1500 mL", "2500 mL", "6000 mL", "10000 mL"]'::jsonb, 2, 'Average adult TLC is approximately 6 litres (6000 mL), though this varies with age, sex, and body size.', 'Pre-Council', '🎓', true),
(5639, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Forced expiratory volume in one second (FEV1) measures:', '["The total volume exhaled during a maximal forced expiration", "The volume of air forcefully exhaled in the first second of a forced expiration", "The residual volume", "Tidal volume during exercise"]'::jsonb, 1, 'FEV1 is the volume of air that can be forcefully exhaled in the first second following maximal inspiration, a key spirometric measure of airflow limitation.', 'Pre-Council', '🎓', true),
(5640, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Forced vital capacity (FVC) refers to:', '["The total volume forcefully exhaled after maximal inspiration", "Residual volume only", "Tidal volume during quiet breathing", "The volume inhaled forcefully"]'::jsonb, 0, 'FVC is the total volume of air that can be forcefully exhaled after a maximal inspiration, measured during spirometry.', 'Pre-Council', '🎓', true),
(5641, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'A reduced FEV1/FVC ratio is characteristic of which pattern of lung disease?', '["Restrictive", "Obstructive", "Normal lung function", "Neither restrictive nor obstructive"]'::jsonb, 1, 'Obstructive lung diseases (e.g. asthma, COPD) disproportionately reduce FEV1 relative to FVC because airflow, particularly during expiration, is impaired.', 'Pre-Council', '🎓', true),
(5642, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'In restrictive lung disease, spirometry typically shows:', '["Reduced FEV1/FVC ratio with normal or increased lung volumes", "Reduced FVC and TLC with a normal or increased FEV1/FVC ratio", "Increased TLC", "Normal FVC with reduced FEV1/FVC"]'::jsonb, 1, 'Restrictive diseases reduce overall lung volumes (FVC, TLC) because the lungs cannot expand normally, but since airflow itself isn''t obstructed, the FEV1/FVC ratio is often normal or even increased.', 'Pre-Council', '🎓', true),
(5643, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which condition would most likely increase residual volume and total lung capacity due to air trapping?', '["Pulmonary fibrosis", "Emphysema", "Pneumonia", "Chest wall restriction"]'::jsonb, 1, 'Emphysema causes loss of elastic recoil and airway collapse during expiration, trapping air and increasing residual volume and often total lung capacity.', 'Pre-Council', '🎓', true),
(5644, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Minute ventilation is calculated as:', '["Tidal volume divided by respiratory rate", "Tidal volume multiplied by respiratory rate", "Vital capacity multiplied by respiratory rate", "Residual volume multiplied by respiratory rate"]'::jsonb, 1, 'Minute ventilation (total air moved per minute) equals tidal volume multiplied by respiratory rate.', 'Pre-Council', '🎓', true),
(5645, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Alveolar ventilation differs from minute ventilation because alveolar ventilation:', '["Includes dead space ventilation", "Subtracts dead space ventilation from total minute ventilation, reflecting only air reaching functional alveoli", "Is always greater than minute ventilation", "Ignores respiratory rate"]'::jsonb, 1, 'Alveolar ventilation accounts for the fact that some of each breath fills anatomical dead space and never reaches gas-exchanging alveoli, so it is calculated as (tidal volume - dead space) x respiratory rate.', 'Pre-Council', '🎓', true),
(5646, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Shallow, rapid breathing (same minute ventilation as normal breathing but smaller tidal volumes with higher rate) tends to:', '["Improve alveolar ventilation", "Reduce alveolar ventilation because a larger proportion of each breath fills dead space", "Have no effect on gas exchange", "Only affect oxygenation, not CO2 elimination"]'::jsonb, 1, 'Because dead space volume is relatively fixed, shallow rapid breathing wastes proportionally more of each breath on dead space, reducing effective alveolar ventilation even if total minute ventilation is unchanged.', 'Pre-Council', '🎓', true),
(5647, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Peak expiratory flow rate (PEFR) is a bedside measurement most useful for monitoring:', '["Restrictive lung disease severity", "Obstructive airway conditions such as asthma", "Residual volume", "Diffusion capacity"]'::jsonb, 1, 'PEFR reflects large airway function and is commonly used to monitor asthma severity and response to treatment/bronchodilators.', 'Pre-Council', '🎓', true),
(5648, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'An increased residual volume relative to total lung capacity (RV/TLC ratio) is most suggestive of:', '["Restrictive lung disease", "Air trapping, as in obstructive lung disease", "Normal lung aging only", "Pneumothorax"]'::jsonb, 1, 'A high RV/TLC ratio reflects air trapping typical of obstructive diseases like emphysema and chronic bronchitis, where airways collapse prematurely during expiration.', 'Pre-Council', '🎓', true),
(5649, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Which lung volume/capacity would be expected to decrease the most in a patient with severe pulmonary fibrosis?', '["Residual volume only", "Total lung capacity and vital capacity", "Tidal volume only, with all other volumes normal", "FEV1/FVC ratio increases without volume changes"]'::jsonb, 1, 'Fibrosis stiffens lung tissue and reduces its ability to expand, lowering overall lung volumes including total lung capacity and vital capacity.', 'Pre-Council', '🎓', true),
(5650, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Functional residual capacity is clinically important because it represents:', '["The volume available for maximal effort inspiration", "The lung volume at which the outward recoil of the chest wall equals the inward recoil of the lungs, acting as an oxygen reservoir between breaths", "The volume that must always be forcefully exhaled", "A measurement with no clinical significance"]'::jsonb, 1, 'FRC represents the resting balance point of the respiratory system and serves as an oxygen reservoir during the brief periods between breaths, which is why maintaining adequate FRC (e.g. via PEEP) is important in critically ill patients.', 'Pre-Council', '🎓', true),
(5651, 'Respiratory System', 'CCN Curriculum — Applied Human Anatomy & Physiology, Unit I', 'Positive end-expiratory pressure (PEEP) during mechanical ventilation is used partly to:', '["Decrease functional residual capacity", "Maintain or increase functional residual capacity and prevent alveolar collapse", "Increase residual volume abnormally", "Reduce oxygenation"]'::jsonb, 1, 'PEEP keeps alveoli open at the end of expiration, helping maintain FRC, prevent atelectasis, and improve oxygenation in patients with conditions like ARDS.', 'Pre-Council', '🎓', true);
